import{_ as a,o as t,c as i,i as o}from"./chunks/framework.DP1yFSuu.js";const u=JSON.parse('{"title":"Figma & Design Access FAQ","description":"Common questions about Figma access, supported design tooling, plugins, and handoff expectations.","frontmatter":{"title":"Figma & Design Access FAQ","description":"Common questions about Figma access, supported design tooling, plugins, and handoff expectations."},"headers":[],"relativePath":"faqs/figma-and-design-access.md","filePath":"faqs/figma-and-design-access.md"}'),s={name:"faqs/figma-and-design-access.md"};function n(r,e,l,d,h,c){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="figma-design-access-faq" tabindex="-1">Figma &amp; Design Access FAQ <a class="header-anchor" href="#figma-design-access-faq" aria-label="Permalink to &quot;Figma &amp; Design Access FAQ&quot;">​</a></h1><p>These questions cover how designers get into the Cobalt design resources and what the docs currently treat as the supported design workflow.</p><h2 id="how-do-i-get-access-to-the-cobalt-figma-team-or-library" tabindex="-1">How do I get access to the Cobalt Figma team or library? <a class="header-anchor" href="#how-do-i-get-access-to-the-cobalt-figma-team-or-library" aria-label="Permalink to &quot;How do I get access to the Cobalt Figma team or library?&quot;">​</a></h2><p>The docs currently provide general access guidance rather than a full internal provisioning workflow.</p><ul><li>Request access through the <a href="/cobalt-design-system/resources/contact.html">Contact</a> path.</li><li>Once access is granted, enable the Cobalt libraries in <strong>Assets &gt; Team Library</strong>.</li><li>If your organization has additional internal approval or group-membership steps, follow those local instructions as well.</li></ul><p>The <a href="/cobalt-design-system/getting-started/designers.html">Getting Started for Designers</a> page is the canonical starting point.</p><h2 id="which-figma-libraries-should-i-enable" tabindex="-1">Which Figma libraries should I enable? <a class="header-anchor" href="#which-figma-libraries-should-i-enable" aria-label="Permalink to &quot;Which Figma libraries should I enable?&quot;">​</a></h2><p>Once you have access to the Cobalt Figma team, enable the <code>Cobalt Design System [MVP]</code> library.</p><h2 id="which-plugins-are-required-versus-optional" tabindex="-1">Which plugins are required versus optional? <a class="header-anchor" href="#which-plugins-are-required-versus-optional" aria-label="Permalink to &quot;Which plugins are required versus optional?&quot;">​</a></h2><p>Today’s docs support this split:</p><ul><li><strong>Required for token sync workflows:</strong> <a href="https://www.figma.com/community/plugin/843461159747178978/tokens-studio-for-figma" target="_blank" rel="noreferrer">Tokens Studio</a></li><li><strong>Helpful but optional:</strong> contrast and accessibility helper plugins such as Contrast or Able</li></ul><p>If you are only consuming the library and not working on token synchronization, Tokens Studio may be less central day to day, but it is still the documented token plugin in the current workflow.</p><h2 id="is-figma-the-primary-design-workflow-today" tabindex="-1">Is Figma the primary design workflow today? <a class="header-anchor" href="#is-figma-the-primary-design-workflow-today" aria-label="Permalink to &quot;Is Figma the primary design workflow today?&quot;">​</a></h2><p>Yes. Figma is the explicitly documented design-tool workflow in the current site.</p><p>The strongest documentation support today is for:</p><ul><li>Cobalt libraries in Figma</li><li>Tokens Studio-based token workflows</li><li>Figma handoff into development</li></ul><h2 id="are-penpot-or-adobe-xd-supported-right-now" tabindex="-1">Are Penpot or Adobe XD supported right now? <a class="header-anchor" href="#are-penpot-or-adobe-xd-supported-right-now" aria-label="Permalink to &quot;Are Penpot or Adobe XD supported right now?&quot;">​</a></h2><p>Not as first-class documented workflows.</p><p>Older docs language may imply broader tool coverage, but the current practical guidance is Figma-first. Until dedicated Penpot or XD setup pages exist, treat Figma as the canonical design workflow.</p><h2 id="what-should-designers-hand-off-to-developers" tabindex="-1">What should designers hand off to developers? <a class="header-anchor" href="#what-should-designers-hand-off-to-developers" aria-label="Permalink to &quot;What should designers hand off to developers?&quot;">​</a></h2><p>At minimum, the handoff should make these things explicit:</p><ul><li>which tokens or styles were used</li><li>supported states</li><li>supported sizes</li><li>theme differences</li><li>component-specific exceptions</li><li>accessibility notes such as labels, focus behavior, and error handling</li></ul><p>The full handoff template lives in <a href="/cobalt-design-system/contributing/figma-handoff.html">Figma Handoff</a>.</p><h2 id="when-should-i-ask-for-a-new-token-instead-of-inventing-a-figma-only-style" tabindex="-1">When should I ask for a new token instead of inventing a Figma-only style? <a class="header-anchor" href="#when-should-i-ask-for-a-new-token-instead-of-inventing-a-figma-only-style" aria-label="Permalink to &quot;When should I ask for a new token instead of inventing a Figma-only style?&quot;">​</a></h2><p>Ask for a new token whenever the value represents a reusable system rule or a value that needs to survive handoff into code. Do not create private Figma-only values for system behavior.</p><p>Use the token decision tree in:</p><ul><li><a href="/cobalt-design-system/tokens/structure.html">Token Structure</a></li><li><a href="/cobalt-design-system/contributing/figma-handoff.html">Figma Handoff</a></li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/cobalt-design-system/getting-started/designers.html">Getting Started for Designers</a></li><li><a href="/cobalt-design-system/contributing/figma-handoff.html">Figma Handoff</a></li><li><a href="/cobalt-design-system/tokens/structure.html">Token Structure</a></li><li><a href="/cobalt-design-system/resources/designers.html">Designer Resources</a></li></ul>',29)])])}const f=a(s,[["render",n]]);export{u as __pageData,f as default};
